let telegramMessage = $input.first().json.message.text.toUpperCase();
const x = '/TODOLIST';
const y = '/INPROGRESS';
const w = '/DONE';

if (telegramMessage.includes(x)) {
  telegramMessage = 'To do';
}  else if (telegramMessage.includes(y)){
  telegramMessage = 'In progress';
} else if (telegramMessage.includes(w)){
  telegramMessage = 'Done';
}
else {  // ← Added "else" here
  telegramMessage = 'FALSE';
}

const notionStatusFilter = {

    "property": "Status",
    "status": {
      "equals": telegramMessage

  }

}

return [
  { 
    json: {  // ← Changed to lowercase "json"
      telegramMessage: telegramMessage,
      userId: $input.first().json.message.from.id,
      filterNotion : JSON.stringify(notionStatusFilter)
    }
  }
];

const items = $input.all();
const chatId = $('Telegram Trigger').item.json.message.chat.id;

// Separate tasks by status
const todoTasks = items.filter(item => item.json.property_status === 'To do');
const inProgressTasks = items.filter(item => item.json.property_status === 'In progress');
const doneTasks = items.filter(item => item.json.property_status === 'Done');

// Helper function for priority emojis
function getPriorityEmoji(priority) {
  const map = { 
    'High': '🔴', 
    'Medium': '🟡', 
    'Low': '🟢' 
  };
  return map[priority] || '⚪';
}

// Build simple message
let message = "📋 *Your Tasks*\n\n";
message += `📊 Overview:\n`;
message += `• To Do: ${todoTasks.length}\n`;
message += `• In Progress: ${inProgressTasks.length}\n`;
message += `• Done: ${doneTasks.length}\n`;
message += `• Total: ${items.length}\n\n`;
message += `👇 *Select a task to view details*`;

// Create buttons array
const buttons = [];

// TO DO Section Buttons
if (todoTasks.length > 0) {
  todoTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} 📝 ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}

// IN PROGRESS Section Buttons
if (inProgressTasks.length > 0) {
  inProgressTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} 🔄 ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}

// DONE Section Buttons
if (doneTasks.length > 0) {
  doneTasks.forEach((item) => {
    const task = item.json;
    const priority = getPriorityEmoji(task.property_priority);

    buttons.push([{
      text: `${priority} ✅ ${task.property_name.substring(0, 35)}`,
      callback_data: `view_${task.id}`
    }]);
  });
}


// Create Telegram API payload
const telegramPayload = {
  chat_id: chatId,
  text: message,
  parse_mode: "Markdown",
  reply_markup: {
    inline_keyboard: buttons
  }
};

return [{
  json: {
    telegramPayload: telegramPayload
  }
}];

const items = $input.all();

// Separate tasks by status
const todoTasks = items.filter(item => item.json.property_status === 'To do');
const inProgressTasks = items.filter(item => item.json.property_status === 'In progress');
const doneTasks = items.filter(item => item.json.property_status === 'Done');

// Calculate totals and percentages
const total = items.length;
const todoCount = todoTasks.length;
const inProgressCount = inProgressTasks.length;
const doneCount = doneTasks.length;

const todoPercent = total > 0 ? ((todoCount / total) * 100).toFixed(1) : 0;
const inProgressPercent = total > 0 ? ((inProgressCount / total) * 100).toFixed(1) : 0;
const donePercent = total > 0 ? ((doneCount / total) * 100).toFixed(1) : 0;

// Helper function to sort tasks by due date
function sortByDueDate(tasks) {
  return tasks.sort((a, b) => {
    const dateA = a.json.property_due_date?.start || '9999-12-31';
    const dateB = b.json.property_due_date?.start || '9999-12-31';
    return dateA.localeCompare(dateB);
  });
}

// Sort all task lists by due date
const sortedTodo = sortByDueDate([...todoTasks]);
const sortedInProgress = sortByDueDate([...inProgressTasks]);
const sortedDone = sortByDueDate([...doneTasks]);

// Function to create table data
function createTableData(tasks) {
  return tasks.map(task => ({
    dueDate: task.json.property_due_date?.start || 'Not set',
    taskName: task.json.property_name,
    status: task.json.property_status,
    priority: task.json.property_priority,
    category: task.json.property_category
  }));
}

// Create table data for each status
const todoTableData = createTableData(sortedTodo);
const inProgressTableData = createTableData(sortedInProgress);
const doneTableData = createTableData(sortedDone);

// Get today's date
const reportDate = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Count high priority tasks
const highPriorityPending = [...todoTasks, ...inProgressTasks].filter(
  t => t.json.property_priority === 'High'
).length;

// Get upcoming deadlines (next 3 days)
const today = new Date();
const threeDaysLater = new Date(today.getTime() + (3 * 24 * 60 * 60 * 1000));
const upcomingTasks = [...todoTasks, ...inProgressTasks].filter(task => {
  const dueDate = task.json.property_due_date?.start;
  if (!dueDate) return false;
  const due = new Date(dueDate);
  return due >= today && due <= threeDaysLater;
});

// Create summary for LLM
const summaryForLLM = {
  date: reportDate,
  statistics: {
    total: total,
    todo: { count: todoCount, percentage: todoPercent },
    inProgress: { count: inProgressCount, percentage: inProgressPercent },
    done: { count: doneCount, percentage: donePercent }
  },
  todoTasks: todoTableData,
  inProgressTasks: inProgressTableData,
  doneTasks: doneTableData,
  completionRate: donePercent,
  highPriorityPending: highPriorityPending,
  upcomingDeadlines: upcomingTasks.length
};

// Create detailed prompt for LLM
const promptForLLM = `You are a professional task management analyst. Analyze the following task data and provide strategic insights.

REPORT DATE: ${reportDate}

OVERALL STATISTICS:
- Total Tasks: ${total}
- To Do: ${todoCount} tasks (${todoPercent}%)
- In Progress: ${inProgressCount} tasks (${inProgressPercent}%)
- Done: ${doneCount} tasks (${donePercent}%)
- Completion Rate: ${donePercent}%

KEY METRICS:
- High Priority Pending: ${highPriorityPending} tasks
- Upcoming Deadlines (3 days): ${upcomingTasks.length} tasks

TO DO TASKS (${todoCount}) - Sample:
${todoTableData.slice(0, 8).map(t => `- ${t.taskName} (${t.priority} priority, Due: ${t.dueDate})`).join('\n')}
${todoCount > 8 ? `... and ${todoCount - 8} more` : ''}

IN PROGRESS TASKS (${inProgressCount}) - Sample:
${inProgressTableData.slice(0, 8).map(t => `- ${t.taskName} (${t.priority} priority, Due: ${t.dueDate})`).join('\n')}
${inProgressCount > 8 ? `... and ${inProgressCount - 8} more` : ''}

COMPLETED TASKS (${doneCount}) - Recent:
${doneTableData.slice(0, 5).map(t => `- ${t.taskName}`).join('\n')}
${doneCount > 5 ? `... and ${doneCount - 5} more` : ''}

Please provide a professional analysis with these sections:

**EXECUTIVE SUMMARY** (3-4 sentences)
Brief overview of task management performance and current status

**KEY INSIGHTS** (4-5 bullet points)
Important observations about:
- Completion rate and productivity
- Priority distribution
- Workload balance
- Any patterns or trends

**RECOMMENDATIONS** (4-5 bullet points)
Actionable suggestions for:
- Task prioritization
- Time management
- Workflow optimization
- Capacity planning

**RISK ASSESSMENT**
Identify any concerns about:
- Overdue or upcoming deadlines
- Workload bottlenecks
- Resource allocation

Keep the tone professional, data-driven, and actionable. Use clear formatting with headers.`;

// Return structured data
return [{
  json: {
    prompt: promptForLLM,
    reportData: summaryForLLM,
    statistics: {
      total: total,
      todoCount: todoCount,
      inProgressCount: inProgressCount,
      doneCount: doneCount,
      todoPercent: todoPercent,
      inProgressPercent: inProgressPercent,
      donePercent: donePercent
    },
    tables: {
      todo: todoTableData,
      inProgress: inProgressTableData,
      done: doneTableData
    }
  }
}];

