const allTasks = [
  ...tables.todo,      // Spreads the array items
  ...tables.inProgress,
  ...tables.done
];

// Define sort order for status and priority
const statusOrder = {
  'To do': 1,
  'In progress': 2,
  'Done': 3
};

const priorityOrder = {
  'High': 1,
  'Medium': 2,
  'Low': 3
};

// Sort combined tasks by status → priority → due date
allTasks.sort((a, b) => {
  // First, sort by status
  const statusCompare = statusOrder[a.status] - statusOrder[b.status];
  if (statusCompare !== 0) return statusCompare;

  // Then, sort by priority within same status
  const priorityCompare = priorityOrder[a.priority] - priorityOrder[b.priority];
  if (priorityCompare !== 0) return priorityCompare;

  // Finally, sort by due date within same priority
  const dateA = a.dueDate === 'Not set' ? '9999-12-31' : a.dueDate;
  const dateB = b.dueDate === 'Not set' ? '9999-12-31' : b.dueDate;
  return dateA.localeCompare(dateB);
});

